const inicioDesafio = new Date(2026, 1, 1); // 01/02/2026

const dataString = $json.date_time; // vem do node anterior
const data = new Date(dataString);

const diffEmMs = data - inicioDesafio;
const diffEmDias = Math.floor(diffEmMs / (1000 * 60 * 60 * 24));

let semana = null;

if (diffEmDias >= 0 && diffEmDias <= 83) {
  semana = Math.floor(diffEmDias / 7) + 1;
}

return {
  semana: semana
};

